Create apps/frontend/lib/governance/finalization.ts. Implement aggregateVotesForFinalization(proposalId: string): Promise<FinalizationData>

interface FinalizationData {
  proposalId: string;
  voters: string[];        // Array of voter addresses
  votes: boolean[];        // Array of votes (true=UPVOTE, false=DOWNVOTE)
  signatures: string[];    // Array of signature hex strings
  nonces: string[];        // Array of nonces
  upvoteCount: number;
  downvoteCount: number;
  totalVoters: number;
  participationRate: number;
  passThresholdMet: boolean; // 2/3 majority
}

async function aggregateVotesForFinalization(proposalId: string): Promise<FinalizationData> {
  // Query all SignedVote records for proposal where submittedOnChain=false
  const signedVotes = await prisma.signedVote.findMany({
    where: { proposalId, submittedOnChain: false },
    orderBy: { createdAt: 'asc' } // Consistent ordering
  });

  // Transform to parallel arrays for contract call
  const voters = signedVotes.map(v => v.walletAddress);
  const votes = signedVotes.map(v => v.voteType === 'UPVOTE');
  const signatures = signedVotes.map(v => v.signature);
  const nonces = signedVotes.map(v => v.nonce);

  // Calculate metrics
  const upvoteCount = votes.filter(v => v).length;
  const downvoteCount = votes.filter(v => !v).length;
  const totalVoters = signedVotes.length;

  // Calculate participation rate (query total user count)
  const totalUsers = await prisma.user.count();
  const participationRate = (totalVoters / totalUsers) * 100;

  // Check 2/3 majority
  const passThresholdMet = upvoteCount >= (totalVoters * 2 / 3);

  return { proposalId, voters, votes, signatures, nonces, upvoteCount, downvoteCount, totalVoters, participationRate, passThresholdMet };
}

