const PLATFORM_SIGNER_PRIVATE_KEY = process.env.PLATFORM_SIGNER_PRIVATE_KEY!;

export const POST = async (req: NextRequest) => {
  const proposalId = req.nextUrl.pathname.split('/')[3];

  // Validate proposal can be finalized
  const proposal = await prisma.proposal.findUnique({ where: { id: proposalId }, include: { signedVotes: true }});
  if (!proposal) return NextResponse.json({ error: 'Not found' }, { status: 404 });
  if (proposal.onChainStatus === 'FINALIZED' || proposal.onChainStatus === 'PASSED' || proposal.onChainStatus === 'FAILED') {
    return NextResponse.json({ error: 'Already finalized' }, { status: 400 });
  }
  if (new Date() < proposal.votingEndsAt!) return NextResponse.json({ error: 'Voting not ended' }, { status: 400 });

  // Check quorum (50% participation)
  const totalUsers = await prisma.user.count();
  const voterCount = proposal.signedVotes.length;
  const quorumMet = (voterCount / totalUsers) >= 0.6;
  if (!quorumMet) return NextResponse.json({ error: 'Quorum not met', participation: voterCount/totalUsers }, { status: 400 });

  // Aggregate votes
  const finalizationData = await aggregateVotesForFinalization(proposalId);

  // Submit to blockchain
  const wallet = new Wallet(PLATFORM_SIGNER_PRIVATE_KEY, new AlchemyProvider('sepolia', process.env.ALCHEMY_API_KEY));
  const contract = createGovernanceContractWithSigner(wallet);

  const tx = await contract.finalizeProposal(
    proposal.onChainId!,
    finalizationData.voters,
    finalizationData.votes,
    finalizationData.signatures
  );

  // Update proposal status to PENDING_ONCHAIN
  await prisma.proposal.update({
    where: { id: proposalId },
    data: { onChainStatus: 'PENDING_ONCHAIN' }
  });

  // Wait for confirmation
  const receipt = await tx.wait();

  // Parse ProposalFinalized event
  const event = receipt.logs.find(log => contract.interface.parseLog(log)?.name === 'ProposalFinalized');
  const parsed = contract.interface.parseLog(event!);
  const passed = parsed!.args.passed;

  // Update database
  await prisma.$transaction(async (tx) => {
    await tx.proposal.update({
      where: { id: proposalId },
      data: {
        finalizationTxHash: receipt.hash,
        onChainStatus: passed ? 'PASSED' : 'FAILED',
        status: passed ? 'APPROVED' : 'REJECTED' // Update legacy status too
      }
    });

    // Mark signatures as submitted
    await tx.signedVote.updateMany({
      where: { proposalId },
      data: { submittedOnChain: true }
    });
  });

  return NextResponse.json({
    success: true,
    txHash: receipt.hash,
    passed,
    upvotes: finalizationData.upvoteCount,
    downvotes: finalizationData.downvoteCount
  });
};

