    where: { id: proposal.id },
    data: {
      finalizationTxHash: event.transactionHash,
      onChainStatus: passed ? 'PASSED' : 'FAILED',
      status: passed ? 'APPROVED' : 'REJECTED',
      updatedAt: new Date()
    }
  });

  console.log(`Proposal ${proposal.id} finalized on-chain: ${passed ? 'PASSED' : 'FAILED'}`);
}

