import { useEffect, useState } from 'react';
import { Clock } from 'lucide-react';
import { Badge } from '@/components/ui/badge';
import { Progress } from '@/components/ui/progress';

interface VotingCountdownProps {
  votingEndsAt: Date | string;
  showProgress?: boolean;
  votingDuration?: number; // in seconds, default 7 days
}

export function VotingCountdown({ votingEndsAt, showProgress = true, votingDuration = 604800 }: VotingCountdownProps) {
  const [timeRemaining, setTimeRemaining] = useState<number>(0);
  const [isEnded, setIsEnded] = useState(false);

  useEffect(() => {
    const calculateTimeRemaining = () => {
      const end = typeof votingEndsAt === 'string' ? new Date(votingEndsAt) : votingEndsAt;
      const now = new Date();
      const diff = end.getTime() - now.getTime();

      if (diff <= 0) {
        setIsEnded(true);
        setTimeRemaining(0);
      } else {
        setIsEnded(false);
        setTimeRemaining(diff);
      }
    };

    calculateTimeRemaining();
    const interval = setInterval(calculateTimeRemaining, 1000);

    return () => clearInterval(interval);
  }, [votingEndsAt]);

  const formatTime = (ms: number) => {
    const seconds = Math.floor(ms / 1000);
    const days = Math.floor(seconds / 86400);
    const hours = Math.floor((seconds % 86400) / 3600);
    const minutes = Math.floor((seconds % 3600) / 60);
    const secs = seconds % 60;

    if (days > 0) return `${days}d ${hours}h ${minutes}m`;
    if (hours > 0) return `${hours}h ${minutes}m ${secs}s`;
    if (minutes > 0) return `${minutes}m ${secs}s`;
    return `${secs}s`;
  };

  const progressPercent = showProgress 
    ? Math.max(0, Math.min(100, ((votingDuration * 1000 - timeRemaining) / (votingDuration * 1000)) * 100))
    : 0;

  if (isEnded) {
    return (
      <Badge variant="secondary">
        <Clock className="mr-1 h-3 w-3" />
        Voting Ended
      </Badge>
    );
  }

  return (
    <div className="space-y-2">
      <div className="flex items-center gap-2">
        <Clock className="h-4 w-4 text-muted-foreground" />
        <span className="text-sm font-medium">
          {formatTime(timeRemaining)} remaining
        </span>
      </div>
      {showProgress && (
        <Progress value={progressPercent} className="h-2" />
      )}
    </div>
  );
}

