import { expect } from 'chai';
import { ethers } from 'hardhat';
import { W3Governance } from '../typechain-types';
import { SignerWithAddress } from '@nomicfoundation/hardhat-ethers/signers';

describe('W3Governance', () => {
  let governance: W3Governance;
  let owner: SignerWithAddress;
  let proposer: SignerWithAddress;
  let voter1: SignerWithAddress;
  let voter2: SignerWithAddress;
  let voter3: SignerWithAddress;

  beforeEach(async () => {
    [owner, proposer, voter1, voter2, voter3] = await ethers.getSigners();

    const W3GovernanceFactory = await ethers.getContractFactory('W3Governance');
    governance = await W3GovernanceFactory.deploy();
  });

  describe('createProposal', () => {
    it('should create proposal and emit ProposalCreated event', async () => {
      const contentHash = ethers.keccak256(ethers.toUtf8Bytes('Test Proposal'));
      const votingDuration = 7 * 24 * 60 * 60; // 7 days

      await expect(governance.connect(proposer).createProposal(contentHash, votingDuration))
        .to.emit(governance, 'ProposalCreated')
        .withArgs(1, proposer.address, contentHash, anyValue);

      const proposal = await governance.getProposal(1);
      expect(proposal.contentHash).to.equal(contentHash);
      expect(proposal.proposer).to.equal(proposer.address);
    });

    it('should increment proposal count', async () => {
      const contentHash = ethers.keccak256(ethers.toUtf8Bytes('Test'));

      await governance.createProposal(contentHash, 3600);
      await governance.createProposal(contentHash, 3600);

      expect(await governance.proposalCount()).to.equal(2);
    });
  });

  describe('vote', () => {
    let proposalId: number;

    beforeEach(async () => {
      const contentHash = ethers.keccak256(ethers.toUtf8Bytes('Test'));
      await governance.createProposal(contentHash, 3600);
      proposalId = 1;
    });

    it('should record vote and emit VoteCast event', async () => {
      await expect(governance.connect(voter1).vote(proposalId, true))
        .to.emit(governance, 'VoteCast')
        .withArgs(proposalId, voter1.address, true, anyValue);

      const [hasVoted, support] = await governance.getVote(proposalId, voter1.address);
      expect(hasVoted).to.be.true;
      expect(support).to.be.true;
    });

    it('should update vote counts', async () => {
      await governance.connect(voter1).vote(proposalId, true);
      await governance.connect(voter2).vote(proposalId, true);
      await governance.connect(voter3).vote(proposalId, false);

      const proposal = await governance.getProposal(proposalId);
      expect(proposal.upvotes).to.equal(2);
      expect(proposal.downvotes).to.equal(1);
    });

    it('should reject double voting', async () => {
      await governance.connect(voter1).vote(proposalId, true);

      await expect(
        governance.connect(voter1).vote(proposalId, false)
      ).to.be.revertedWith('Already voted');
    });

    it('should reject voting after deadline', async () => {
      await ethers.provider.send('evm_increaseTime', [3601]);
      await ethers.provider.send('evm_mine', []);

      await expect(
        governance.connect(voter1).vote(proposalId, true)
      ).to.be.revertedWith('Voting ended');
    });
  });

  describe('finalizeProposal', () => {
    it('should finalize with 2/3 majority and mark as passed', async () => {
      const contentHash = ethers.keccak256(ethers.toUtf8Bytes('Test'));
      await governance.createProposal(contentHash, 1); // 1 second voting

      // Cast votes
      await governance.connect(voter1).vote(1, true);
      await governance.connect(voter2).vote(1, true);
      await governance.connect(voter3).vote(1, false);

      await ethers.provider.send('evm_increaseTime', [2]);
      await ethers.provider.send('evm_mine', []);

      await expect(governance.finalizeProposal(1))
        .to.emit(governance, 'ProposalFinalized')
        .withArgs(1, 2, 1, true);

      const proposal = await governance.getProposal(1);
      expect(proposal.finalized).to.be.true;
      expect(proposal.passed).to.be.true;
    });

    it('should mark as failed with <2/3 majority', async () => {
      const contentHash = ethers.keccak256(ethers.toUtf8Bytes('Test'));
      await governance.createProposal(contentHash, 1);

      await governance.connect(voter1).vote(1, true);
      await governance.connect(voter2).vote(1, false);
      await governance.connect(voter3).vote(1, false);

      await ethers.provider.send('evm_increaseTime', [2]);
      await ethers.provider.send('evm_mine', []);

      const tx = await governance.finalizeProposal(1);
      const receipt = await tx.wait();

      const proposal = await governance.getProposal(1);
      expect(proposal.passed).to.be.false;
    });

    it('should revert if voting period not ended', async () => {
      const contentHash = ethers.keccak256(ethers.toUtf8Bytes('Test'));
      await governance.createProposal(contentHash, 3600);

      await expect(
        governance.finalizeProposal(1)
      ).to.be.revertedWith('Voting not ended');
    });

    it('should revert if already finalized', async () => {
      const contentHash = ethers.keccak256(ethers.toUtf8Bytes('Test'));
      await governance.createProposal(contentHash, 1);

      await ethers.provider.send('evm_increaseTime', [2]);
      await ethers.provider.send('evm_mine', []);

      await governance.finalizeProposal(1);

      await expect(
        governance.finalizeProposal(1)
      ).to.be.revertedWith('Already finalized');
    });
  });
});

